import sailpoint.object.*;
import sailpoint.tools.*;
import java.util.*;

// Log the start of workflow
workflowStartTime = new Date();
requestId = UUID.randomUUID().toString();

log.info("=== Create AD Group Workflow Started ===");
log.info("Request ID: " + requestId);
log.info("Application Name: " + applicationName);
log.info("Group Name: " + groupName);

// Validate required input parameters
List errors = new ArrayList();

if (null == applicationName || applicationName.trim().isEmpty()) {
  errors.add("applicationName is required");
}

if (null == groupName || groupName.trim().isEmpty()) {
  errors.add("groupName is required");
}

if (null == groupDescription || groupDescription.trim().isEmpty()) {
  errors.add("groupDescription is required");
}

if (null == groupOwner || groupOwner.trim().isEmpty()) {
  errors.add("groupOwner is required");
}

if (null == groupType || groupType.trim().isEmpty()) {
  errors.add("groupType is required");
}
// Validate groupType values
else if (!groupType.equals("Security") && !groupType.equals("Distribution")) {
  errors.add("groupType must be either 'Security' or 'Distribution'");
}

if (null == groupScope || groupScope.trim().isEmpty()) {
  errors.add("groupScope is required");
}
// Validate groupScope values
else if (!groupScope.equals("Global") && !groupScope.equals("Domain Local") && !groupScope.equals("Universal")) {
  errors.add("groupScope must be 'Global', 'Domain Local', or 'Universal'");
}

if (null == organizationalUnit || organizationalUnit.trim().isEmpty()) {
  errors.add("organizationalUnit is required");
}

if (errors.size() > 0) {
  errorMessage = "Validation Failed: " + errors.toString();
  isSuccess = false;
  log.error(errorMessage);
  workflow.put("validationErrors", errors);
  return false;
}

isSuccess = true;
log.info("All validations passed");
return true;

import sailpoint.object.*;
import sailpoint.tools.*;

log.info("Retrieving Active Directory application: " + applicationName);

// Get the AD application object
adApplication = context.getObjectByName(Application.class, applicationName);

if (null == adApplication) {
  errorMessage = "Active Directory application not found: " + applicationName;
  isSuccess = false;
  log.error(errorMessage);
  return false;
}

log.info("AD Application found successfully");
log.info("Application Key: " + adApplication.getName());

isSuccess = true;
return true;

import sailpoint.object.*;
import sailpoint.tools.*;
import sailpoint.connector.*;
import java.util.*;

log.info("Building provisioning plan for group creation");

try {
  // Create a new ProvisioningPlan
  ProvisioningPlan plan = new ProvisioningPlan();
  plan.setComments("Create AD Group - API Request ID: " + requestId);

  // Create account request for group creation
  ProvisioningPlan.AccountRequest acctReq = new ProvisioningPlan.AccountRequest(ProvisioningPlan.AccountRequest.Type.Create, applicationName, null, null);

  // Add the primary group attributes
  Map attributes = new HashMap();

  // Set group name
  attributes.put("sAMAccountName", groupName);

  // Set group display name
  attributes.put("cn", groupName);
  attributes.put("displayName", groupName);

  // Set description
  attributes.put("description", groupDescription);

  // Set group type
  if ("Security".equals(groupType)) {
    attributes.put("groupType", "-2147483646"); // ADS_GROUP_TYPE_SECURITY_ENABLED
  } else if ("Distribution".equals(groupType)) {
    attributes.put("groupType", "2"); // ADS_GROUP_TYPE_UNIVERSAL_GROUP
  }

  // Set group scope
  attributes.put("groupScope", groupScope);

  // Set organizational unit
  attributes.put("ou", organizationalUnit);

  // Set managed by (owner)
  attributes.put("managedBy", groupOwner);

  // Set group email if provided
  if (null != groupEmail && !groupEmail.trim().isEmpty()) {
    attributes.put("mail", groupEmail);
  }

  // Add additional attributes if provided
  if (null != additionalAttributes && additionalAttributes.size() > 0) {
    attributes.putAll(additionalAttributes);
    log.info("Added " + additionalAttributes.size() + " additional attributes");
  }

  // Add attributes to account request
  for (String attrName : attributes.keySet()) {
    ProvisioningPlan.AttributeRequest attrReq = new ProvisioningPlan.AttributeRequest(attrName, ProvisioningPlan.Operation.Set, attributes.get(attrName));
    acctReq.add(attrReq);
    log.debug("Added attribute: " + attrName + " = " + attributes.get(attrName));
  }

  // Add account request to plan
  plan.add(acctReq);

  // Store the plan in workflow
  workflow.put("provisioningPlan", plan);

  log.info("Provisioning plan built successfully with " + attributes.size() + " attributes");
  isSuccess = true;
  return true;

} catch (Exception e) {
  errorMessage = "Error building provisioning plan: " + e.getMessage();
  isSuccess = false;
  log.error(errorMessage, e);
  return false;
}

import sailpoint.object.*;
import sailpoint.tools.*;
import sailpoint.connector.*;
import java.util.*;

log.info("Executing provisioning plan to create AD group");

try {
  ProvisioningPlan plan = (ProvisioningPlan) workflow.get("provisioningPlan");

  if (null == plan) {
    errorMessage = "Provisioning plan not found in workflow";
    isSuccess = false;
    log.error(errorMessage);
    return false;
  }

  // Get the connector for the AD application
  Connector connector = adApplication.getConnector();

  if (null == connector) {
    errorMessage = "Connector not found for application: " + applicationName;
    isSuccess = false;
    log.error(errorMessage);
    return false;
  }

  // Execute the provisioning plan
  connectorProvisioning = connector.provision(context, adApplication, plan);

  if (null != connectorProvisioning) {
    log.info("Provisioning executed successfully");
    log.info("Provisioning result: " + connectorProvisioning.toString());
    isSuccess = true;
  } else {
    errorMessage = "Provisioning returned null result";
    isSuccess = false;
    log.warn(errorMessage);
  }

  return isSuccess;

} catch (Exception e) {
  errorMessage = "Error executing provisioning: " + e.getMessage();
  isSuccess = false;
  log.error(errorMessage, e);
  return false;
}

import sailpoint.object.*;
import sailpoint.tools.*;
import java.util.*;
import java.text.*;

log.info("Creating audit log entry");

try {
  String status = isSuccess ? "SUCCESS" : "FAILED";
  Date endTime = new Date();
  long duration = endTime.getTime() - workflowStartTime.getTime();

  auditLog = "Request ID: " + requestId + " | " +
             "Status: " + status + " | " +
             "Application: " + applicationName + " | " +
             "Group Name: " + groupName + " | " +
             "Owner: " + groupOwner + " | " +
             "Duration: " + duration + "ms";

  // Create audit entry
  AuditEvent event = new AuditEvent();
  event.setAction("CreateADGroup");
  event.setSource("CreateADGroupWorkflow");
  event.setInterface("API");
  event.setStatus(status);
  event.setComment(auditLog);
  event.setAttributes(new HashMap());
  event.getAttributes().put("requestId", requestId);
  event.getAttributes().put("applicationName", applicationName);
  event.getAttributes().put("groupName", groupName);
  event.getAttributes().put("groupOwner", groupOwner);
  event.getAttributes().put("duration", String.valueOf(duration));

  // Save audit event
  context.saveObject(event);
  context.commitTransaction();

  log.info("Audit log created successfully");
  log.info(auditLog);

} catch (Exception e) {
  log.error("Error creating audit log: " + e.getMessage(), e);
}

import sailpoint.object.*;
import sailpoint.tools.*;

log.error("=== Workflow encountered error ===");
log.error("Error Message: " + errorMessage);
log.error("Request ID: " + requestId);

// You can add additional error handling here such as:
// - Sending notifications
// - Creating tickets
// - Rolling back changes

workflow.put("error", errorMessage);
workflow.put("isSuccess", isSuccess);
